import React, { useState, useEffect } from 'react';
import ProductTypeForm from './ProductTypeForm';
import { getProductTypes, deleteProductType } from '../services/api';

const filterOptions = ['Active Product Types', 'All Product Types'];
const allColumns = [
  { field: 'id', label: 'id' },
  { field: 'display_name', label: 'Display Name' },
  { field: 'api_name', label: 'API Name' },
  { field: 'asset_type', label: 'Asset Type' },
  { field: 'asset_category_type', label: 'Asset Category' },
  { field: 'description', label: 'Description' },
];

const ProductTypeTable = () => {
  const [productTypes, setProductTypes] = useState([]);
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState(null);
  const [activeFilter, setActiveFilter] = useState(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState(null);
  const [actionRow, setActionRow] = useState(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState(null);
  const [visibleColumns, setVisibleColumns] = useState([
    'display_name',
    'api_name',
    'asset_type',
    'asset_category_type',
    'description',
  ]);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  useEffect(() => {
    fetchProductTypes();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      // Close columns dropdown if clicking outside
      if (columnsAnchorEl && !columnsAnchorEl.contains(event.target)) {
        const dropdown = document.querySelector('[data-columns-dropdown]');
        if (dropdown && !dropdown.contains(event.target)) {
          setColumnsAnchorEl(null);
        }
      }
      
      // Close action menu if clicking outside
      if (actionAnchorEl && !actionAnchorEl.contains(event.target)) {
        const actionMenu = document.querySelector('[data-action-menu]');
        if (actionMenu && !actionMenu.contains(event.target)) {
          setActionAnchorEl(null);
        }
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [columnsAnchorEl, actionAnchorEl]);

  const fetchProductTypes = async () => {
    try {
      const response = await getProductTypes();
      setProductTypes(response.data);
    } catch (error) {
      console.error('Error fetching product types:', error);
    }
  };

  const handleOpen = (item = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = () => {
    fetchProductTypes();
    handleClose();
  };

  const handleDelete = async (id) => {
    try {
      await deleteProductType(id);
      fetchProductTypes();
    } catch (error) {
      console.error('Error deleting product type:', error);
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
  };

  const getParentProductTypeDisplay = (item, visited = new Set()) => {
    if (!item.parent_product_type) {
      return item.display_name;
    }

    const parentValue = item.parent_product_type;
    let parent = null;

    if (typeof parentValue === 'object' && parentValue !== null) {
      parent = parentValue;
    } else {
      parent = productTypes.find((pt) => {
        const parentId = pt.id?.toString();
        const parentDisplay = pt.display_name;
        const valueString = parentValue?.toString();
        return parentId === valueString || parentDisplay === parentValue;
      });
    }

    if (!parent) {
      return item.display_name;
    }

    const parentIdKey = parent.id?.toString() || parent.display_name;
    if (visited.has(parentIdKey)) {
      return `${parent.display_name} >> ${item.display_name}`;
    }

    visited.add(parentIdKey);
    const parentDisplay = getParentProductTypeDisplay(parent, visited);
    return `${parentDisplay} >> ${item.display_name}`;
  };

  const totalPages = Math.ceil(productTypes.length / pageSize);
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedData = productTypes.slice(startIndex, endIndex);

  const handlePageChange = (page) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handlePageSizeChange = (e) => {
    setPageSize(parseInt(e.target.value));
    setCurrentPage(1);
  };

  return (
    <div>
      <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between space-y-4 md:space-y-0">
          <div className="flex flex-col md:flex-row md:items-center space-y-2 md:space-y-0 md:space-x-2">
            <select
              value={activeFilter}
              onChange={(e) => setActiveFilter(e.target.value)}
              className="w-full md:w-64 px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {filterOptions.map((option) => (
                <option key={option} value={option}>
                  {option}
                </option>
              ))}
            </select>
            <button
              onClick={() => handleOpen()}
              className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 flex items-center space-x-2"
            >
              <span>✎</span>
              <span>New</span>
            </button>
          </div>

          <div className="flex space-x-2">
            <button
              onClick={handleClearFilters}
              className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Clear All Filters
            </button>
            <div className="relative">
              <button
                onClick={(e) => setColumnsAnchorEl(e.currentTarget)}
                className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 flex items-center space-x-2"
              >
                <span>▶</span>
                <span>Select Columns</span>
              </button>
              {columnsAnchorEl && (
                <div className="absolute z-10 bg-white border border-gray-300 rounded-md shadow-lg p-2 top-full right-0 mt-1" data-columns-dropdown>
                  {allColumns.map((column) => (
                    <label
                      key={column.field}
                      className="flex items-center space-x-2 p-1 hover:bg-gray-100 cursor-pointer"
                      onClick={() => {
                        setVisibleColumns((prev) =>
                          prev.includes(column.field)
                            ? prev.filter((value) => value !== column.field)
                            : [...prev, column.field]
                        );
                        setColumnsAnchorEl(null);
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={visibleColumns.includes(column.field)}
                        onChange={() => {}}
                        className="rounded"
                      />
                      <span>{column.label}</span>
                    </label>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* {columnsAnchorEl && (
        <div className="absolute z-10 bg-white border border-gray-300 rounded-md shadow-lg p-2">
          {allColumns.map((column) => (
            <label key={column.field} className="flex items-center space-x-2 p-1 hover:bg-gray-100 cursor-pointer">
              <input
                type="checkbox"
                checked={visibleColumns.includes(column.field)}
                onChange={() => setVisibleColumns((prev) =>
                  prev.includes(column.field)
                    ? prev.filter((value) => value !== column.field)
                    : [...prev, column.field]
                )}
                className="rounded"
              />
              <span>{column.label}</span>
            </label>
          ))}
        </div>
      )} */}

      <div className="bg-white rounded-lg shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="w-14 px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"></th>
                {visibleColumns.includes('id') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    id
                  </th>
                )}
                {visibleColumns.includes('display_name') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Display Name
                  </th>
                )}
                {visibleColumns.includes('api_name') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    API Name
                  </th>
                )}
                {visibleColumns.includes('asset_type') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Asset Type
                  </th>
                )}
                {visibleColumns.includes('asset_category_type') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Asset Category
                  </th>
                )}
                {visibleColumns.includes('description') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Description
                  </th>
                )}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {paginatedData.map((item) => (
                <tr key={item.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    <button
                      onClick={(event) => {
                        event.stopPropagation();
                        setActionRow(item);
                        setActionAnchorEl(event.currentTarget);
                      }}
                      className="text-gray-400 hover:text-gray-600"
                    >
                      ⋮
                    </button>
                  </td>
                  {visibleColumns.includes('id') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.id}</td>}
                  {visibleColumns.includes('display_name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{getParentProductTypeDisplay(item)}</td>}
                  {visibleColumns.includes('api_name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.api_name}</td>}
                  {visibleColumns.includes('asset_type') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.asset_type}</td>}
                  {visibleColumns.includes('asset_category_type') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.asset_category_type}</td>}
                  {visibleColumns.includes('description') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.description}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Pagination Controls */}
      <div className="bg-white rounded-lg shadow-sm p-4 mt-6 flex flex-col md:flex-row md:items-center md:justify-between">
        <div className="flex items-center space-x-2 mb-4 md:mb-0">
          <label className="text-sm text-gray-700">Page Size:</label>
          <select
            value={pageSize}
            onChange={handlePageSizeChange}
            className="px-3 py-1 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex items-center space-x-4">
          <span className="text-sm text-gray-700">
            {productTypes.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, productTypes.length)} of ${productTypes.length}`}
          </span>

          <div className="flex items-center space-x-2">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="px-3 py-1 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              ← Prev
            </button>

            <span className="text-sm text-gray-700">
              Page {currentPage} of {totalPages === 0 ? 1 : totalPages}
            </span>

            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="px-3 py-1 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Next →
            </button>
          </div>
        </div>
      </div>

      {actionAnchorEl && (
        <div 
          className="absolute z-10 bg-white border border-gray-300 rounded-md shadow-lg" 
          data-action-menu
          style={{
            top: actionAnchorEl ? actionAnchorEl.getBoundingClientRect().bottom + window.scrollY : 0,
            left: actionAnchorEl ? actionAnchorEl.getBoundingClientRect().left + window.scrollX : 0,
          }}
        >
          <button
            onClick={() => {
              if (actionRow) handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Edit
          </button>
          <button
            onClick={() => {
              if (actionRow) handleDelete(actionRow.id);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Delete
          </button>
        </div>
      )}

      {open && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="flex items-center justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
            <div className="fixed inset-0 transition-opacity" aria-hidden="true">
              <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={handleClose}></div>
            </div>
            <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-lg sm:w-full">
              <div className="bg-white px-4 pt-5 pb-4 sm:p-6 sm:pb-4">
                <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4">
                  {editing ? 'Edit Product Type' : 'New Product Type'}
                </h3>
                <ProductTypeForm
                  editing={editing}
                  onSave={handleSave}
                  onClose={handleClose}
                  productTypes={productTypes}
                />
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductTypeTable;
